resources.string:
[
  {
    "name": "com.aeonos.portalha.set_screen",
    "description": "Turn this Meta Portal's display on (wake it) or off (sleep/lock the screen).",
    "parameters": {
      "type": "object",
      "properties": {
        "on": { "type": "boolean", "description": "true = wake the screen, false = turn the screen off." }
      },
      "required": ["on"]
    }
  },
  {
    "name": "com.aeonos.portalha.set_camera",
    "description": "Turn this Portal's camera (the Home Assistant video stream) on or off.",
    "parameters": {
      "type": "object",
      "properties": {
        "on": { "type": "boolean", "description": "true = enable the camera, false = disable it." }
      },
      "required": ["on"]
    }
  },
  {
    "name": "com.aeonos.portalha.get_presence",
    "description": "Check whether someone is currently present in front of this Portal (room occupancy).",
    "parameters": { "type": "object", "properties": {} }
  },
  {
    "name": "com.aeonos.portalha.home_assistant",
    "description": "Control the user's smart home, or ask about its state, in plain English through Home Assistant - lights, switches, scenes, climate, locks, covers, media and more. Pass the request verbatim, e.g. 'turn on the porch lights', 'run the goodnight scene', or 'is the garage door open?'. Use this for any home-automation request.",
    "parameters": {
      "type": "object",
      "properties": {
        "command": { "type": "string", "description": "The user's natural-language smart-home request or question." }
      },
      "required": ["command"]
    }
  },
  {
    "name": "com.aeonos.portalha.home_assistant_service",
    "description": "Advanced: call a specific Home Assistant service directly when the exact domain, service and entity are known (more precise than the plain-language tool). Example: domain 'light', service 'turn_on', entity_id 'light.kitchen'.",
    "parameters": {
      "type": "object",
      "properties": {
        "domain": { "type": "string", "description": "Service domain, e.g. 'light', 'switch', 'scene', 'climate', 'lock'." },
        "service": { "type": "string", "description": "Service name, e.g. 'turn_on', 'turn_off', 'toggle', 'set_temperature'." },
        "entity_id": { "type": "string", "description": "Target entity id, e.g. 'light.kitchen'. Optional for services that don't need one." },
        "data_json": { "type": "string", "description": "Optional extra service data as a JSON object string, e.g. {'brightness_pct': 50}." }
      },
      "required": ["domain", "service"]
    }
  }
]
